scwin.f_defaultValue = function () {
  $c.gus.cfDisableKey($p);
  $c.gus.cfDisableBtn($p, [btn_save]);
  $c.gus.cfDisableObjects($p, [oRecevInfo]);
  acb_wrkPlClsCd.setDisabled(true);
  udc_adddistrict.setDisabled(true);
  ed_cnd_wrkPlNm.focus();
};
scwin.f_addRow_gr_wrkpl = async function () {
  scwin.f_ds_district_copy();
  const newRowIndex = ds_wrkpl.getRowCount();
  const oldRowIndex = ds_wrkpl.getRowPosition();

  // oRecevInfo 
  if (!$c.util.isEmpty($p, oldRowIndex)) {
    let chk = await scwin.f_ReqFieldChk(oldRowIndex);
    if (chk == false) {
      ds_wrkpl.setEventPause("onrowpositionchange", true);
      gr_wrkpl.setFocusedCell(oldRowIndex, 0);
      ds_wrkpl.setEventPause("onrowpositionchange", false);
      if (typeof chk.comObj == "function") {
        chk.comObj();
      } else {
        if (chk?.comObj?.focus) {
          chk.comObj.focus();
        }
      }
      return false;
    }
    $c.gus.cfEnableBtnOnly($p, [btn_save]);
    ds_wrkpl.insertRow(newRowIndex);
    acb_wrkPlClsCd.setDisabled(false);
    acb_wrkPlClsCd.setValue("R");
    // 기본 입력 값 설정 
    ds_wrkpl.setCellData(newRowIndex, "hndlRateOutbrYn", 0); // 조작료발생여부
    ds_wrkpl.setCellData(newRowIndex, "preInfoSndYn", 0); // 사전정보전송여부
    ds_wrkpl.setCellData(newRowIndex, "gatelogSndYn", 0); // GateLog전송여부
    ds_wrkpl.setCellData(newRowIndex, "ediSndYn", 0); // EDI사용여부
    ds_wrkpl.setCellData(newRowIndex, "cntrRgnWrkPlYn", 1); // CNTR작업장여부
    ds_wrkpl.setCellData(newRowIndex, "cgshfRateOutbrYn", 0); // 이적료발생여부 
    ds_wrkpl.setCellData(newRowIndex, "useYn", 1); // 사용 여부 
    gr_wrkpl.setFocusedCell(newRowIndex, "wrkPlClsNm", false);
  }
};
scwin.f_delRow_gr_wrkpl = async function () {
  const oldRowIndex = ds_wrkpl.getRowPosition();
  const newRowIndex = oldRowIndex - 1;
  if (oldRowIndex < 0) return false;
  if (ds_wrkpl.getRowStatus(oldRowIndex) == "C") {
    const rowFilterCount = ds_district.getRowCount();
    for (let rowIdx = 0; rowIdx < rowFilterCount; rowIdx++) {
      scwin.f_rowUndo(ds_district, [rowIdx]);
    }
    scwin.f_rowUndo(gr_wrkpl, [oldRowIndex]);
  } else {
    if (oldRowIndex > -1) {
      $c.data.deleteRow($p, gr_wrkpl);
      const rowFilterCount = ds_district.getRowCount();
      for (let rowIdx = 0; rowIdx < rowFilterCount; rowIdx++) {
        ds_district.setRowPosition(rowIdx);
        $c.data.deleteRow($p, ds_district);
      }
      let chk = await scwin.f_ReqFieldChk(oldRowIndex);
      if (chk == false) {
        //ds_wrkpl.setEventPause("onrowpositionchange",true);
        gr_wrkpl.setFocusedCell(oldRowIndex, 0);
        //ds_wrkpl.setEventPause("onrowpositionchange",false);
        if (typeof chk.comObj == "function") {
          chk.comObj();
        } else {
          if (chk?.comObj?.focus) {
            chk.comObj.focus();
          }
        }
        return false;
      }
      gr_wrkpl.setFocusedCell(newRowIndex, 0);
      scwin.f_districtFilter();
    }
  }
};
scwin.f_cancel_gr_wrkpl = function () {
  scwin.f_rowUndo(gr_wrkpl, true);
};
scwin.f_addRow_gr_district = function () {
  $c.gus.cfEnableBtnOnly($p, [btn_save]);
  if (ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(), "wrkPlCd") == "") {
    $c.win.alert($p, scwin.MSG_LO_ERR_006);
    return;
  }
  var row = ds_district.getRowCount();
  ds_district.insertRow(row);
  ds_district.setCellData(row, "wrkPlCd", ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(), "wrkPlCd"));
  ds_district.setCellData(row, "wrkPlNm", ds_wrkpl.getCellData(ds_wrkpl.getRowPosition(), "wrkPlNm"));
  gr_district.setFocusedCell(row, "districtCd", false);
};
scwin.f_rowUndo = function (gridObj, rowIndexList = []) {
  let rowIdxs = [];
  const length = gridObj.getRowCount();
  if (rowIndexList instanceof Array) {
    rowIndexList = rowIndexList.length == 0 ? Array.from({
      length
    }, (_, i) => i) : rowIndexList;
    rowIdxs = rowIndexList.filter(f => f > -1);
  } else {
    rowIdxs = gridObj.getAllFocusedRowIndex();
  }
  let dataList = $p.getComponentById(gridObj.getDataList());
  let removeIdx = [];
  let undoIdx = [];
  let onlyRFlag = false;
  for (let idx in rowIdxs) {
    var row = rowIdxs[idx];
    if (dataList.getRowStatus(row) == "C") {
      removeIdx.push(row);
      onlyRFlag = true;
    } else {
      undoIdx.push(row);
      if (onlyRFlag) {
        onlyRFlag = false;
      }
    }
  }
  let tRemoveIdx = removeIdx.length;
  let tUndoIdx = undoIdx.length;
  if (removeIdx.length > 0) {
    dataList.removeRows(removeIdx);
    if (onlyRFlag) {
      if (dataList.getRowCount() > 0) {
        if (dataList.getRowCount() - 1 < removeIdx[0]) {
          gridObj.setFocusedCell(dataList.getRowCount() - 1, 0);
        } else {
          gridObj.setFocusedCell(removeIdx[0], 0);
        }
      }
    }
  }
  if (undoIdx.length > 0) {
    dataList.undoRows(undoIdx);
    if (dataList.getRowCount() > 0) {
      gridObj.setFocusedCell(undoIdx[tUndoIdx - 1], 0);
    }
  }
};

//-------------------------------------------------------------------------
// scwin.name : f_Retrieve
// scwin.desc : 조회
//-------------------------------------------------------------------------

scwin.f_Retrieve = function () {
  scwin.gr_wrkpl_sortOptions = gr_wrkpl.getSortableStatus().reduce((s, a, i) => {
    if (!s["sortIndex"]) s["sortIndex"] = "";
    if (!s["sortOrder"]) s["sortOrder"] = "";
    s["sortIndex"] += (i == 0 ? "" : " ") + a["colID"];
    s["sortOrder"] += (i == 0 ? "" : " ") + a["sortOrder"];
    return s;
  }, {});
  ds_wrkpl.removeAll();
  ds_district.removeAll();
  ds_district_send.removeAll();
  $c.sbm.execute($p, sbm_retrieve);
};
scwin.sbm_retrieve_submitdone = function (e) {
  if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

  var rowcnt = ds_wrkpl.getRowCount();
  if (rowcnt == 0) {
    $c.win.alert($p, MSG_CM_WRN_002);
    gr_wrkpl.setFocusedCell(0, 0);
  } else {
    $c.gus.cfEnableObjects($p, [oRecevInfo]);
    $c.gus.cfDisableKey($p);
    if (scwin.gr_wrkpl_sortOptions && scwin.gr_wrkpl_sortOptions["sortIndex"]) {
      ds_wrkpl.multisort(scwin.gr_wrkpl_sortOptions);
    }
    // gr_wrkpl.setFocusedCell(scwin?.pos_rowSts||0, 0);
    let ds_wrkpl_pos = 0;
    ds_wrkpl.setIgnoreStatus("rowIndex", true);
    ds_wrkpl.getAllJSON().forEach((row, rowIndex) => {
      if (!$c.util.isEmpty($p, scwin.pos_wrkPlCd)) {
        if (row.wrkPlCd == scwin.pos_wrkPlCd) {
          ds_wrkpl_pos = rowIndex;
        }
      }
      ds_wrkpl.setCellData(rowIndex, "rowIndex", rowIndex);
    });
    gr_wrkpl.setFocusedCell(ds_wrkpl_pos, 0);
  }
  scwin.pos_rowSts = 0;
  scwin.pos_wrkPlCd = null;
  tbx_totalRows.setValue(rowcnt);
  $c.gus.cfDisableBtn($p, [btn_save]);
  acb_wrkPlClsCd.setDisabled(true);
  udc_adddistrict.setDisabled(false);
};
scwin.sbm_retrieve_submiterror = function (e) {};

