scwin.f_ds_district_copy = function () {
  const sendList = ds_district.getAllJSON().filter(f => f.rowStatus != "R");
  ds_district_send.removeAll();
  sendList.forEach((rowJson, rowIndex) => {
    ds_district_send.setRowJSON(rowIndex, rowJson);
    ds_district_send.modifyRowStatus(rowIndex, rowJson.rowStatus);
  });
};
scwin.f_Save = async function () {
  scwin.f_ds_district_copy();
  if (ds_wrkpl.getModifiedJSON().length == 0 && ds_district_send.getModifiedJSON().length == 0) {
    $c.gus.cfAlertMsg($p, $c.data.getMessage($p, MSG_CM_ERR_001, ["철도역"]));
    return false;
  }
  ed_wrkPlNm.setValue(ed_wrkPlNm.getValue().trim());
  let chk = await scwin.f_ReqFieldChk_save();
  if (chk) {
    chk = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (chk) {
      scwin.pos_rowSts = ds_wrkpl.getRowPosition();
      scwin.pos_wrkPlCd = ds_wrkpl.getCellData(scwin.pos_rowSts, "wrkPlCd");
      $c.sbm.execute($p, sbm_save);
    }
  }
};
scwin.f_ReqFieldChk_save = async function (rowIndex) {
  //필수입력항목 체크
  if (rd_UseYn.getValue() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("사용여부"));
    return false;
  }
  if (acb_wrkPlClsCd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("작업장구분"));
    return false;
  }

  // oRecevInfo
  let chk = await $c.gus.cfValidate($p, [oRecevInfo]);
  if (!chk) {
    return false;
  }
  chk = await $c.gus.cfValidate($p, [gr_district], null, true);
  if (!chk) {
    return false;
  }
  if (ed_lobranCd.getValue() == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("소속점소"));
    ed_lobranCd.focus();
    return false;
  }
  if (ds_wrkpl.getRowStatus(ds_wrkpl.getRowPosition()) == "C" && ed_lobranCd.getValue().substr(0, 1) + acb_wrkPlClsCd.getValue() != ed_wrkPlCd.getValue().substr(0, 2) && acb_wrkPlClsCd.getValue() != "G") {
    await $c.win.alert($p, scwin.MSG_LO_ERR_007);
    ed_wrkPlCd.setValue(ed_lobranCd.getValue().substr(0, 1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2, 3));
    for (i = 0; i < ds_district.getRowCount(); i++) {
      ds_district.setCellData(i, "wrkPlCd", ed_lobranCd.getValue().substr(0, 1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2, 3));
    }
    return false;
  }

  // 철도역별 지역코드 Check
  const checkList = ds_wrkpl.getAllJSON().filter(f => {
    const rowStatusCheck = ['C', 'U'].includes(f.rowStatus); // 등록 수정 일경우 
    const districtCountCheck = ds_district.getAllJSON().filter(fc => fc.wrkPlCd == f.wrkPlCd).length == 0; // 소속 지역 건수 가 O인 경우 
    return rowStatusCheck && districtCountCheck;
  });
  if (checkList.length > 0) {
    await $c.win.alert($p, scwin.MSG_LO_ERR_009);
    return false;
  }
  return true;
};
scwin.f_ReqFieldChk = async function (rowIndex) {
  const resultInfo = function (check, comObj) {
    return {
      comObj,
      valueOf() {
        return check;
      }
    };
  };
  if (rowIndex < 0) return true;
  const {
    rowStatus,
    wrkPlClsCd,
    lobranCd,
    wrkPlCd,
    wrkPlNm,
    useYn,
    zip,
    addr1,
    addr2,
    korailStnCd
  } = ds_wrkpl.getRowJSON(rowIndex);
  if (wrkPlClsCd == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("작업장구분"));
    return resultInfo(false, acb_wrkPlClsCd);
  }
  if (wrkPlCd == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("작업장코드"));
    return resultInfo(false, ed_wrkPlCd);
  }
  if (lobranCd == "" && (rowStatus == "C" || rowStatus == "U")) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("소속점소"));
    return resultInfo(false, ed_lobranCd);
  }
  if (wrkPlNm == "" || wrkPlNm.length > 50) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("작업장명"));
    return resultInfo(false, ed_wrkPlNm);
  }
  if (zip == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("우편번호"));
    return resultInfo(false, ed_zip);
  }
  if (addr1 == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("주소"));
    return resultInfo(false, ed_addr1);
  }
  if (addr2 == "" || addr2.length > 50) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("상세주소"));
    return resultInfo(false, ed_addr2);
  }
  if (korailStnCd == "" || korailStnCd.length > 6) {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("철도청역코드"));
    return resultInfo(false, ed_korailStnCd);
  }

  //필수입력항목 체크
  if (useYn == "") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("사용여부"));
    return false;
  }
  const districtList = ds_district.getAllFilteredJSON();

  // 소속 지역코드 필수 CHECK 
  const districtMsg = $c.str.attachPostposition($p, "지역코드");
  // - 건수 
  if (districtList.length == 0 && rowStatus == "D") {
    await $c.gus.cfAlertMsg($p, MSG_CM_WRN_007, new Array("지역코드"));
    return false;
  }

  // 소속점소
  // await $c.gus.cfAlertMsg(`소속지역의 ${N}번재 데이터에서 지역코드은(는) 필수 입력 항목입니다.`);
  const emptyCheckList = districtList.map((o, row) => {
    return {
      ...o,
      row
    };
  }).filter(f => f["districtCd"] + f["districtNm"] == "");
  if (emptyCheckList.length > 0) {
    const emptyRowIndex = emptyCheckList.at(0)["row"];
    await $c.gus.cfAlertMsg($p, `소속지역의 ${emptyRowIndex + 1}번재 데이터에서 ${districtMsg} 필수 입력 항목입니다.`);
    return false;
  }

  // - 중복 
  // 소속지역의 N번재 데이터에서 지역코드은(는) 중복될 수 없습니다.   N  - 1 아님
  const duplicateKey = "districtCd";
  const keyMap = districtList.reduce((acc, item, idx) => {
    acc[item[duplicateKey]] = acc[item[duplicateKey]] ?? [];
    acc[item[duplicateKey]].push(idx);
    return acc;
  }, {});
  const duplicateList = Object.entries(keyMap).filter(([key, rows]) => rows.length > 1).map(([key, rows]) => {
    const [first, ...duplicates] = rows;
    return {
      key,
      minRow: Math.min(...duplicates),
      first,
      duplicates
    };
  });
  console.log("result===>", duplicateList);
  if (duplicateList.length > 0) {
    const duplicateInfo = duplicateList.at(0);
    await $c.gus.cfAlertMsg($p, `소속지역의 ${duplicateInfo["minRow"] + 1}번재 데이터에서 ${districtMsg} 중복될 수 없습니다.`);
    return false;
  }
  // rowIndex
  if (rowStatus == "C" && lobranCd.substr(0, 1) + wrkPlClsCd != wrkPlCd.substr(0, 2) && wrkPlClsCd != "G") {
    await $c.win.alert($p, scwin.MSG_LO_ERR_007);
    const failFn = function () {
      ed_wrkPlCd.setValue(ed_lobranCd.getValue().substr(0, 1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2, 3));
      for (i = 0; i < ds_district.getRowCount(); i++) {
        ds_district.setCellData(i, "wrkPlCd", ed_lobranCd.getValue().substr(0, 1) + acb_wrkPlClsCd.getValue() + ed_wrkPlCd.getValue().substr(2, 3));
      }
    };
    return resultInfo(false, failFn);
  }
  const sendList = districtList.filter(f => f.rowStatus != "D");
  // 소속점소 목록이 없는 경우 
  if (rowStatus != "D" && sendList.length == 0) {
    await $c.win.alert($p, scwin.MSG_LO_ERR_009);
    return false;
  }
  return true;
};
