scwin.gr_wrkpl_onrowindexchange = async function (rowIndex, oldRow) {
  return false;
  if (scwin._revertingNode == true) {
    scwin._revertingNode = false;
    return false;
  }
  if (oldRow != null && oldRow > -1) {
    const chk = await scwin.f_ReqFieldChk(oldRow);
    if (chk == false) {
      scwin._revertingNode = true;
      gr_wrkpl.setFocusedCell(oldRow, 0);
      if (typeof chk.comObj == "function") {
        chk.comObj();
      } else {
        if (chk.comObj.focus) {
          chk.comObj.focus();
        }
      }
      return false;
    }
  }
  if (rowIndex > -1) {
    $c.gus.cfPrepareObjectHidVal($p, ds_wrkpl, rowIndex, ["lobranCd", "lobranNm", "upperWrkPlCd", "upperWrkPlNm"], [ed_lobranCd, ed_lobranNm, ed_upperWrkPlCd, ed_upperWrkPlNm]);
    $c.gus.cfEnableObjects($p, [oRecevInfo]);
    if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    } else {
      $c.gus.cfDisableKey($p);
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    }
  }
  if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
    acb_wrkPlClsCd.setDisabled(false);
  } else {
    acb_wrkPlClsCd.setDisabled(true);
  }

  //콤보박스 값 세팅
  acb_wrkPlClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd"));
  acb_WrkPlPosnClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd"));
  acb_OwnerCd.setValue(ds_wrkpl.getCellData(rowIndex, "ownerCd"));
  scwin.f_districtFilter();
  tbx_totalRows2.setValue(ds_district.getRowCount());
};
scwin._revertingNode = false;
scwin.ds_wrkpl_onrowpositionchange = async function (info) {
  if (scwin._revertingNode) {
    scwin._revertingNode = false;
    return false;
  }
  const {
    newRowIndex: rowIndex,
    oldRowIndex: oldRow
  } = info;
  if (rowIndex == null) return false;
  if (oldRow != null && oldRow > -1) {
    const chk = await scwin.f_ReqFieldChk(oldRow);
    if (chk == false) {
      scwin._revertingNode = true;
      //            gr_wrkpl.setEventPause("onrowpositionchange",false);
      //            ds_wrkpl.setEventPause("onrowpositionchange",false);
      gr_wrkpl.setFocusedCell(oldRow, 0);
      //            ds_wrkpl.setEventPause("onrowpositionchange",true);
      //            gr_wrkpl.setEventPause("onrowpositionchange",true);
      if (typeof chk.comObj == "function") {
        chk.comObj();
      } else {
        if (chk?.comObj?.focus) {
          chk.comObj.focus();
        }
      }
      return false;
    }
  }
  if (rowIndex > -1) {
    $c.gus.cfPrepareObjectHidVal($p, ds_wrkpl, rowIndex, ["lobranCd", "lobranNm", "upperWrkPlCd", "upperWrkPlNm"], [ed_lobranCd, ed_lobranNm, ed_upperWrkPlCd, ed_upperWrkPlNm]);
    $c.gus.cfEnableObjects($p, [oRecevInfo]);
    if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    } else {
      $c.gus.cfDisableKey($p);
      $c.gus.cfDisableObjects($p, [ed_zip, ed_addr1]);
    }
  }
  if (ds_wrkpl.getRowStatus(rowIndex) == "C") {
    acb_wrkPlClsCd.setDisabled(false);
  } else {
    acb_wrkPlClsCd.setDisabled(true);
  }

  //콤보박스 값 세팅
  acb_wrkPlClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlClsCd"));
  acb_WrkPlPosnClsCd.setValue(ds_wrkpl.getCellData(rowIndex, "wrkPlPosnClsCd"));
  acb_OwnerCd.setValue(ds_wrkpl.getCellData(rowIndex, "ownerCd"));
  scwin.f_districtFilter();
  tbx_totalRows2.setValue(ds_district.getRowCount());
  gr_wrkpl.render.focus();
};
